     1→/**
     2→ * Synapse - Neural Search Interface
     3→ *
     4→ * Quick-access search and navigation for Neuman Brain, accessible via Ctrl+K (Win/Linux) or Cmd+K (Mac).
     5→ * Named after synapses - the connection points in the brain where signals fire rapidly.
     6→ * Provides instant access to notes, tasks, events, settings, and web search.
     7→ */
     8→
     9→import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
    10→import { createPortal } from 'react-dom';
    11→import { useNavigate } from 'react-router-dom';
    12→import { Search, X, ExternalLink, ArrowRight, Settings } from 'lucide-react';
    13→import { useEscapeKey } from '../../hooks/useEscapeKey';
    14→import { searchAll, groupResultsByType, getTypeLabel, detectMode, stripModePrefix, searchCommands, getQuickCreateResult, getRecentCommandResults } from './searchRegistry';
    15→import { SEARCH_ENGINES } from './types';
    16→import type { SearchResult, CommandPaletteMode } from './types';
    17→import { useSettingsStore } from '../../stores/useSettingsStore';
    18→import { useThemeStore } from '../../stores/useThemeStore';
    19→import { CommandPaletteSettings } from './CommandPaletteSettings';
    20→
    21→interface CommandPaletteProps {
    22→  isOpen: boolean;
    23→  onClose: () => void;
    24→  /** Callback to open the support modal with a specific tab */
    25→  onOpenSupportModal?: (tab: 'report' | 'help' | 'docs') => void;
    26→  /** Callback to open other modals by ID (about, privacy, onboarding, etc.) */
    27→  onOpenModal?: (modalId: string) => void;
    28→}
    29→
    30→/**
    31→ * Type icons mapping
    32→ */
    33→const TYPE_ICONS: Record<string, string> = {
    34→  page: '🏠',
    35→  note: '📝',
    36→  task: '✅',
    37→  event: '📅',
    38→  bookmark: '🔗',
    39→  diagram: '📊',
    40→  form: '📋',
    41→  'time-entry': '⏱️',
    42→  external: '🌐',
    43→  action: '🔲',
    44→  faq: '❓',
    45→  help: '💡',
    46→  widget: '🧩',
    47→  setting: '⚙️',
    48→  automation: '⚡',
    49→  template: '📋',
    50→  project: '📁',
    51→  shortcut: '⌨️',
    52→};
    53→
    54→export const CommandPalette: React.FC<CommandPaletteProps> = ({ isOpen, onClose, onOpenSupportModal, onOpenModal }) => {
    55→  const navigate = useNavigate();
    56→  const inputRef = useRef<HTMLInputElement>(null);
    57→  const listRef = useRef<HTMLDivElement>(null);
    58→  const selectedItemRef = useRef<HTMLButtonElement>(null);
    59→
    60→  const [query, setQuery] = useState('');
    61→  const [selectedIndex, setSelectedIndex] = useState(0);
    62→  const [showSettings, setShowSettings] = useState(false);
    63→
    64→  // Get preferred search engine from settings (default to Google)
    65→  const preferredSearchEngine = useSettingsStore(
    66→    (state) => state.commandPalette?.preferredSearchEngine ?? 'google'
    67→  );
    68→  const isDarkMode = useThemeStore((state) => state.mode === 'dark');
    69→
    70→  // Handle escape key - close settings first, then palette
    71→  useEscapeKey({
    72→    enabled: isOpen,
    73→    onEscape: () => {
    74→      if (showSettings) {
    75→        setShowSettings(false);
    76→      } else {
    77→        onClose();
    78→      }
    79→    },
    80→    priority: 10000,
    81→  });
    82→
    83→  // Detect mode from query
    84→  const mode: CommandPaletteMode = useMemo(() => detectMode(query), [query]);
    85→
    86→  // Search results with memoization - handles different modes
