   114→    if (!query.trim()) {
   115→      const recentCommands = getRecentCommandResults(navigate, onOpenModal);
   116→      if (recentCommands.length > 0) {
   117→        // Put recent commands first, then regular results
   118→        return [...recentCommands, ...searchResults];
   119→      }
