  1006→              : `Enter tag name to remove from ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
  1007→          }
  1008→          defaultValue={bulkTagValue}
  1009→          placeholder="Tag name"
  1010→          confirmText={bulkTagAction === 'add' ? 'Add Tag' : 'Remove Tag'}
  1011→        />
  1012→      )}
