  1017→/**
  1018→ * Notes Page Component
  1019→ * Phase 5: Updated with TabNavigation for tabs (Notes, Daily Notes, Graph)
  1020→ */
  1021→export const Notes: React.FC = () => {
  1022→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
  1023→  const getOrCreateDailyNote = useNotesStore((state) => state.getOrCreateDailyNote);
  1024→  const dailyNotesEnabled = useSettingsStore((state) => state.dailyNotes.enabled);
  1025→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  1026→  const [sidebarWidth, setSidebarWidth] = useState(320);
  1027→  const [isResizing, setIsResizing] = useState(false);
  1028→  const sidebarRef = useRef<HTMLDivElement>(null);
  1029→  const [searchParams, setSearchParams] = useSearchParams();
  1030→  const navigate = useNavigate();
  1031→  const [blockId, setBlockId] = useState<string | undefined>();
  1032→
  1033→  // Phase 5: Tab state management
  1034→  const getTabFromUrl = (): NotesTabType => {
  1035→    const tab = searchParams.get('tab');
  1036→    if (tab && VALID_TABS.includes(tab as NotesTabType)) {
  1037→      return tab as NotesTabType;
  1038→    }
  1039→    // Legacy support: ?daily=true maps to daily tab
  1040→    if (searchParams.get('daily') === 'true') {
  1041→      return 'daily';
  1042→    }
  1043→    return 'notes'; // Default tab
  1044→  };
  1045→
  1046→  const [activeTab, setActiveTab] = useState<NotesTabType>(getTabFromUrl);
  1047→
  1048→  // Update tab when URL changes
  1049→  useEffect(() => {
  1050→    const newTab = getTabFromUrl();
  1051→    if (newTab !== activeTab) {
  1052→      setActiveTab(newTab);
  1053→    }
  1054→  }, [searchParams]);
  1055→
  1056→  // Update URL when tab changes
  1057→  const handleTabChange = (tab: NotesTabType) => {
  1058→    setActiveTab(tab);
  1059→    navigate(`/notes?tab=${tab}`, { replace: true });
  1060→  };
  1061→
  1062→  // Tag filtering state
  1063→  const [activeTags, setActiveTags] = useState<string[]>([]);
  1064→  const [showTagManager, setShowTagManager] = useState(false);
  1065→
  1066→  // Template Library state
  1067→  const [showTemplateLibrary, setShowTemplateLibrary] = useState(false);
  1068→  const [showTitlePrompt, setShowTitlePrompt] = useState(false);
  1069→  const [selectedTemplate, setSelectedTemplate] = useState<NoteTemplate | null>(null);
  1070→  const [titleInput, setTitleInput] = useState('');
  1071→
  1072→  // Export Modal state
  1073→  const [showExportModal, setShowExportModal] = useState(false);
  1074→
  1075→  // Get store actions
  1076→  const createNote = useNotesStore((state) => state.createNote);
  1077→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
  1078→
  1079→  const handleAddTag = (tag: string) => {
  1080→    if (!activeTags.includes(tag)) {
  1081→      setActiveTags([...activeTags, tag]);
  1082→    }
  1083→  };
  1084→
  1085→  const handleRemoveTag = (tag: string) => {
  1086→    setActiveTags(activeTags.filter((t) => t !== tag));
  1087→  };
  1088→
  1089→  const handleClearAllTags = () => {
  1090→    setActiveTags([]);
  1091→  };
  1092→
  1093→  // Template selection handlers
  1094→  const handleSelectTemplate = (template: NoteTemplate) => {
  1095→    // Check if template contains {title} variable
  1096→    const variables = extractTemplateVariables(template.description);
  1097→    if (variables.includes('title')) {
  1098→      // Prompt user for title
  1099→      setSelectedTemplate(template);
  1100→      setTitleInput('');
  1101→      setShowTitlePrompt(true);
  1102→      setShowTemplateLibrary(false);
  1103→    } else {
  1104→      // Create note immediately with variable substitution
  1105→      createNoteFromTemplate(template);
  1106→    }
  1107→  };
  1108→
  1109→  const createNoteFromTemplate = (template: NoteTemplate, customTitle?: string) => {
  1110→    // Substitute template variables
  1111→    const context = {
  1112→      title: customTitle,
  1113→      userName: 'User', // Could be fetched from settings in future
  1114→    };
  1115→    const processedContent = substituteTemplateVariables(template.description, context);
  1116→
  1117→    // Create note with template content and tags
  1118→    const newNote = createNote({
  1119→      folderId: activeFolderId,
  1120→      title: customTitle || template.name,
  1121→      contentText: processedContent,
  1122→      tags: template.defaultTags || [],
  1123→      icon: template.icon,
  1124→    });
  1125→
  1126→    log.info('Created note from template', {
  1127→      templateId: template.id,
  1128→      noteId: newNote.id,
  1129→      title: newNote.title,
  1130→    });
  1131→  };
  1132→
  1133→  const handleConfirmTitle = (title: string) => {
  1134→    if (selectedTemplate && title.trim()) {
  1135→      createNoteFromTemplate(selectedTemplate, title.trim());
  1136→      setShowTitlePrompt(false);
  1137→      setSelectedTemplate(null);
  1138→      setTitleInput('');
  1139→    }
  1140→  };
  1141→
  1142→  const handleCancelTitle = () => {
  1143→    setShowTitlePrompt(false);
  1144→    setSelectedTemplate(null);
  1145→    setTitleInput('');
  1146→  };
  1147→
  1148→  useEffect(() => {
  1149→    document.title = 'Notes - Neuman Brain';
  1150→    log.debug('Notes page loaded');
  1151→
  1152→    // Keyboard shortcut for export (Cmd/Ctrl+Shift+E)
  1153→    const handleKeyDown = (e: KeyboardEvent) => {
  1154→      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'E') {
  1155→        e.preventDefault();
  1156→        setShowExportModal(true);
  1157→      }
  1158→    };
  1159→
  1160→    window.addEventListener('keydown', handleKeyDown);
  1161→    return () => window.removeEventListener('keydown', handleKeyDown);
  1162→  }, []);
  1163→
  1164→  // Handle ?daily=true query parameter to open today's daily note
  1165→  useEffect(() => {
  1166→    if (searchParams.get('daily') === 'true' && dailyNotesEnabled) {
  1167→      const today = new Date();
  1168→      getOrCreateDailyNote(today); // Auto-selects the note by setting activeNoteId
