import React from 'react';
import { Modal } from './Modal';
import { Button } from './ui';

interface ConfirmDialogProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  title: string;
  message: string;
  confirmText?: string;
  cancelText?: string;
  variant?: 'danger' | 'warning' | 'info';
}

const variantIcons: Record<string, string> = {
  danger: '🚨',
  warning: '⚠️',
  info: 'ℹ️',
};

/**
 * ConfirmDialog component for in-app confirmations
 * Replaces browser confirm() dialogs
 */
export const ConfirmDialog: React.FC<ConfirmDialogProps> = ({
  isOpen,
  onClose,
  onConfirm,
  title,
  message,
  confirmText = 'Confirm',
  cancelText = 'Cancel',
  variant = 'info',
}) => {
  const handleConfirm = () => {
    onConfirm();
    onClose();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleConfirm();
    }
  };

  // Map dialog variant to button variant
  const buttonVariant = variant === 'danger' ? 'danger' : 'primary';

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} maxWidth="sm">
      <div className="space-y-4" onKeyDown={handleKeyDown}>
        {/* Icon + Message */}
        <div className="flex items-start gap-4">
          <div className="flex-shrink-0 text-3xl">{variantIcons[variant]}</div>
          <p className="text-text-light-secondary dark:text-text-dark-secondary flex-1">{message}</p>
        </div>

        {/* Action Buttons */}
        <div className="flex gap-3 justify-end pt-2">
          <Button variant="outline" onClick={onClose} autoFocus>
            {cancelText}
          </Button>
          <Button variant={buttonVariant} onClick={handleConfirm}>
            {confirmText}
          </Button>
        </div>
      </div>
    </Modal>
  );
};

