     1→/**
     2→ * Focus Trap Hook
     3→ * Traps focus within a container element (e.g., modal dialogs)
     4→ * Required for WCAG 2.1 accessibility compliance
     5→ *
     6→ * Features:
     7→ * - Traps Tab/Shift+Tab navigation within container
     8→ * - Focuses first focusable element on mount
     9→ * - Restores focus to trigger element on unmount
    10→ * - Handles escape key to close
    11→ */
    12→
    13→import { useEffect, useRef, useCallback } from 'react';
    14→
    15→/** Selector for all focusable elements */
    16→const FOCUSABLE_SELECTOR = [
    17→  'button:not([disabled])',
    18→  'a[href]',
    19→  'input:not([disabled])',
    20→  'select:not([disabled])',
    21→  'textarea:not([disabled])',
    22→  '[tabindex]:not([tabindex="-1"])',
    23→].join(', ');
    24→
    25→interface UseFocusTrapOptions {
    26→  /** Whether the focus trap is active */
